import { createError, defineEventHandler, readBody } from "h3";
import { useStorage } from "nitro/storage";
import { loadDioEntitlement, normalizeEmail } from "../../../src/dio-provider/server";

interface ClaimBody {
	email?: string;
	purchaseReference?: string;
}

export default defineEventHandler(async (event) => {
	if (event.method !== "POST") {
		throw createError({ statusCode: 405, statusMessage: "Method not allowed" });
	}

	const body = await readBody<ClaimBody>(event);
	const email = normalizeEmail(body?.email ?? "");
	if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
		throw createError({ statusCode: 400, statusMessage: "Valid email is required" });
	}

	const entitlement = await loadDioEntitlement(useStorage("keating:dio"), email);
	if (!entitlement) {
		// Check for a pending purchase record as a hint.
		const pending = await useStorage("keating:dio").getItem(`pending:${email}`);
		if (pending) {
			return { success: false, pending: true };
		}
		return { success: false, pending: false };
	}

	if (
		body?.purchaseReference &&
		entitlement.purchaseReference &&
		entitlement.purchaseReference !== body.purchaseReference
	) {
		return { success: false, pending: false };
	}

	return {
		success: true,
		apiKey: entitlement.virtualKeyValue,
	};
});

