	process.env.BIFROST_BASE_URL = "https://bifrost.test";
	process.env.BIFROST_MODEL_ALIAS = "kimi-k2.6";
});

afterEach(() => {
	for (const [key, value] of Object.entries(envBackup)) {
		if (value === undefined) {
			delete process.env[key];
		} else {
			process.env[key] = value;
