export interface DioEventRecord {
  status: "processing" | "succeeded" | "failed";
  createdAt: string;
  error?: string;
}

const EVENT_KEY_PREFIX = "event:";

export async function acquireEventLock(
  storage: { hasItem: (key: string) => Promise<boolean>; setItem: (key: string, value: unknown) => Promise<void> },
  eventId: string,
): Promise<boolean> {
  const key = `${EVENT_KEY_PREFIX}${eventId}`;
  if (await storage.hasItem(key)) {
    return false;
  }
  const record: DioEventRecord = { status: "processing", createdAt: new Date().toISOString() };
  await storage.setItem(key, record);
  return true;
}

export async function completeEvent(
  storage: { setItem: (key: string, value: unknown) => Promise<void>; getItem: (key: string) => Promise<unknown> },
  eventId: string,
  succeeded: boolean,
  error?: string,
): Promise<void> {
  const key = `${EVENT_KEY_PREFIX}${eventId}`;
  const existing = await storage.getItem(key);
  const record: DioEventRecord = {
    status: succeeded ? "succeeded" : "failed",
    createdAt: (existing && typeof existing === "object" && (existing as DioEventRecord).createdAt) || new Date().toISOString(),
    error,
  };
  await storage.setItem(key, record);
}
```

