const RECOVERY_KEY_PREFIX = "recovery:";

interface RecoveryChallenge {
  email: string;
  otpHash: string;
  expiresAt: string;
  attempts: number;
}

function hashOtp(otp: string): string {
  return createHash("sha256").update(otp).digest("hex");
}

function generateOtp(): string {
  return Array.from({ length: 6 }, () => Math.floor(Math.random() * 10)).join("");
}

export async function createRecoveryChallenge(
  storage: { setItem: (key: string, value: unknown) => Promise<void> },
  email: string,
): Promise<string> {
  const otp = generateOtp();
  const challenge: RecoveryChallenge = {
    email,
    otpHash: hashOtp(otp),
    expiresAt: new Date(Date.now() + 15 * 60 * 1000).toISOString(),
    attempts: 0,
  };
  await storage.setItem(`${RECOVERY_KEY_PREFIX}${email}`, challenge);
  return otp;
}

export async function verifyRecoveryChallenge(
  storage: { getItem: (key: string) => Promise<unknown>; setItem: (key: string, value: unknown) => Promise<void> },
  email: string,
  otp: string,
): Promise<boolean> {
  const key = `${RECOVERY_KEY_PREFIX}${email}`;
  const value = await storage.getItem(key);
  if (!value || typeof value !== "object") return false;
  const challenge = value as RecoveryChallenge;
  if (new Date(challenge.expiresAt) < new Date()) {
    await storage.setItem(key, { ...challenge, attempts: challenge.attempts + 1 });
    return false;
  }
  if (challenge.attempts >= 5) return false;
