+ * Acquire a per-event processing lock using a dedicated storage key.
+ *
+ * Returns false if the event is already processing or has succeeded, which
+ * prevents duplicate Creem webhooks from racing. A previously "failed" event
+ * can be retried.
+ */
+export async function acquireEventLock(
+	storage: { getItem: (key: string) => Promise<unknown>; setItem: (key: string, value: unknown) => Promise<void> },
+	eventId: string,
+): Promise<boolean> {
+	const key = eventStorageKey(eventId);
+	const existing = await storage.getItem(key);
+	if (existing && typeof existing === "object") {
+		const record = existing as DioEventRecord;
+		if (record.status === "processing" || record.status === "succeeded") {
+			return false;
+		}
+	}
+	const record: DioEventRecord = { status: "processing", createdAt: new Date().toISOString() };
+	await storage.setItem(key, record);
+	return true;
+}
+
+export async function completeEvent(
+	storage: { setItem: (key: string, value: unknown) => Promise<void> },
+	eventId: string,
+	succeeded: boolean,
+	error?: string,
+): Promise<void> {
+	const key = eventStorageKey(eventId);
+	const record: DioEventRecord = {
+		status: succeeded ? "succeeded" : "failed",
+		createdAt: new Date().toISOString(),
+		error,
+	};
+	await storage.setItem(key, record);
+}
+
